module RefModule(input[4:0] in, input clk, rst, writeData, output[4:0] out);reg [4:0] unused_outData;
	assign out = unused_outData;
	always@(posedge clk, posedge rst)begin
		if(rst) unused_outData <= 5'b0;
		else
		begin
			if(writeData) unused_outData <= in;
			else unused_outData <= unused_outData;
		end
	end
endmodule
